  PRIMARY KEY (`id`),
  KEY `fk_commande_entreprise` (`idEntreprise`),
  CONSTRAINT `fk_commande_entreprise` FOREIGN KEY (`idEntreprise`) REFERENCES `entreprise` (`idEntreprise`)
